let peso=document.getElementById("peso"),altura=document.getElementById("altura"),btn=document.querySelector(".btn"),imc=0;btn.addEventListener("click",function(e){e.preventDefault();var e=peso.value,i=altura.value;18.5<(imc=e/(i*i))&&imc<24.99?swal(imc.toFixed(2)+" Peso normal","","success"):25<=imc&&imc<29.99?swal(imc.toFixed(2)+" Acima do peso","","warning"):30<=imc&&imc<34.99?swal(imc.toFixed(2)+" Obesidade 1","","error"):swal("Valor indefinido...","","info")});